import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a confidence interval?", a: "A confidence interval is a range of plausible values for a population parameter, such as a population mean. It combines a sample estimate with a margin of error." },
  { q: "How do you calculate a 95% confidence interval?", a: "For a mean, use sample mean plus or minus z times standard deviation divided by the square root of sample size. At 95% confidence, z is about 1.96." },
  { q: "What is the margin of error?", a: "Margin of error is the amount added and subtracted from the sample estimate to form the interval. Smaller standard deviation or larger sample size reduces it." },
  { q: "What does it mean if confidence intervals overlap?", a: "Overlapping confidence intervals suggest estimates may not be clearly different, but overlap alone is not a full significance test. The context and statistical test matter." },
  { q: "What is the difference between confidence interval and prediction interval?", a: "A confidence interval estimates a population parameter such as the mean. A prediction interval estimates where a future individual observation may fall and is usually wider." },
];

const zScores: Record<string, number> = { "90": 1.645, "95": 1.96, "99": 2.576 };
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";

export default function ConfidenceIntervalCalculator() {
  const [mean, setMean] = useState(50);
  const [sd, setSd] = useState(10);
  const [sampleSize, setSampleSize] = useState(100);
  const [confidence, setConfidence] = useState("95");
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (sd < 0 || sampleSize <= 0) return { margin: NaN, lower: NaN, upper: NaN, step: "Use a nonnegative standard deviation and positive sample size.", interpretation: "Invalid input." };
    const z = zScores[confidence];
    const se = sd / Math.sqrt(sampleSize);
    const margin = z * se;
    const lower = mean - margin;
    const upper = mean + margin;
    return { margin, lower, upper, step: `SE = ${sd} / sqrt(${sampleSize}) = ${fmt(se)}. Margin of error = ${z} x ${fmt(se)} = ${fmt(margin)}. CI = ${mean} - ${fmt(margin)}.`, interpretation: `You can report the ${confidence}% confidence interval as ${fmt(lower)} to ${fmt(upper)}. This estimates a plausible range for the population mean.` };
  }, [mean, sd, sampleSize, confidence]);

  return (
    <>
      <SEOHead title="Free Confidence Interval Calculator Online - Calculate CI for Any Dataset Instantly | CalcHive" description="Free online confidence interval calculator. Calculate 90% 95% and 99% confidence intervals from sample mean, standard deviation and sample size instantly. 100% free for researchers, no signup required." canonical="/confidence-interval-calculator" keywords="free confidence interval calculator, confidence interval calculator online free, 95% confidence interval calculator free, calculate confidence interval free, CI calculator statistics free" category="Statistics Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Confidence Interval Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this confidence interval calculator online free to calculate confidence interval free for 90%, 95%, and 99% levels.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label htmlFor="mean" className="text-sm font-semibold text-foreground block mb-2">Sample mean</label><input id="mean" type="number" inputMode="decimal" value={mean} onChange={(event) => setMean(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="sd" className="text-sm font-semibold text-foreground block mb-2">Standard deviation</label><input id="sd" type="number" inputMode="decimal" value={sd} onChange={(event) => setSd(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="sample-size" className="text-sm font-semibold text-foreground block mb-2">Sample size</label><input id="sample-size" type="number" inputMode="numeric" value={sampleSize} onChange={(event) => setSampleSize(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="confidence" className="text-sm font-semibold text-foreground block mb-2">Confidence level</label><select id="confidence" value={confidence} onChange={(event) => setConfidence(event.target.value)} className={inputClass}><option value="90">90%</option><option value="95">95%</option><option value="99">99%</option></select></div>
          </div>
          <motion.div key={`${mean}-${sd}-${sampleSize}-${confidence}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{confidence}% Confidence Interval</p><p className="text-4xl font-black text-white tracking-tight" data-testid="result-confidence-interval">{fmt(result.lower)} to {fmt(result.upper)}</p><p className="text-white/70 text-sm mt-1">Margin of error: {fmt(result.margin)}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-sm text-foreground mb-2">{result.interpretation}</p><p className="text-sm text-foreground font-mono" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate a Confidence Interval for Free</h2><p className="text-muted-foreground leading-relaxed">Enter the sample mean, standard deviation, sample size, and confidence level. This CI calculator statistics free tool returns the lower and upper bounds.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Interpret Your Confidence Interval Results</h2><p className="text-muted-foreground leading-relaxed">The interval gives a plausible range for the population mean based on your sample and selected confidence level.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Statistical CI Calculator for Students and Researchers</h2><p className="text-muted-foreground leading-relaxed">Use this 95% confidence interval calculator free for research summaries, statistics homework, and data reporting.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/confidence-interval-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


